INSERT INTO domain_scores (id, review_id, domain, score, rag_label, overall_readiness, executive_summary, compliant_areas, gap_areas, blocker_count, action_count, adr_count, domain_specific_scores, evidence_quality, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'application', 3, 'amber', 'APPROVE_WITH_CONDITIONS', 'The Bank EDMS is designed as a cloud-native, microservices-based platform on AWS, aligning with modern architectural principles. Key strengths include its microservices approach and focus on independent deployability. However, the submission lacks detailed evidence for compliance with enterprise standards, particularly regarding the tech stack and scalability. Further clarification on these areas is required before development can proceed without conditions.', ARRAY['ARCHITECTURE_STYLE — The solution is designed as a cloud-native, microservices-based platform on AWS, aligning with KB-02.', 'RESILIENCE_PATTERNS — The HLD mentions resilience design, indicating an awareness of the need for HA/failover.']::text[], ARRAY['APP-F01: Tech stack compliance with Jakarta EE/Spring Boot standards.', 'APP-F02: Detailed scalability targets and validation evidence.', 'APP-F03: Compliance mapping to application controls and audit logging.']::text[], 0, 3, 1, NULL, 'PARTIAL', ARRAY['KB-01', 'KB-02', 'KB-03', 'KB-04', 'KB-06']::text[], 'NOW()', 'NOW()');
INSERT INTO domain_scores (id, review_id, domain, score, rag_label, overall_readiness, executive_summary, compliant_areas, gap_areas, blocker_count, action_count, adr_count, domain_specific_scores, evidence_quality, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'solution', 4, 'green', 'APPROVE', 'The Bank EDMS initiative addresses significant regulatory and operational risks stemming from seven disparate document management systems. The proposed solution offers a clear path to consolidation, improved compliance, operational efficiency, and strategic alignment. Key strengths include a well-defined problem statement with measurable outcomes and adherence to core EA principles. While the design is sound, further detail on specific technology standards and economic TCO would enhance completeness.', ARRAY['PROBLEM_STATEMENT_QUALITY: Clear and well-quantified problem statement.', 'SOLUTION_FIT: Direct alignment between problem and proposed EDMS solution.', 'BUSINESS_OUTCOMES: SMART outcomes with measurable KPIs and timelines.', 'STAKEHOLDER_ALIGNMENT: Key stakeholders (LOB CIOs) identified.', 'STRATEGIC_FIT: Aligns with enterprise target state for consolidated, cloud-native platforms.', 'ARCHITECTURE_PRINCIPLES_ADHERENCE: Documented adherence to principles, patterns, and standards.', 'PROCESS_ADHERENCE: Consolidation decisions approved by Architecture Forum.']::text[], ARRAY['SOL-F01: Incomplete detail on economic TCO analysis.', 'SOL-F02: Specific technology standards compliance needs further detail.']::text[], 0, 1, 0, '{"SOLUTION_FIT": 5, "STRATEGIC_FIT": 5, "BUSINESS_OUTCOMES": 5, "STAKEHOLDER_ALIGNMENT": 4, "PROBLEM_STATEMENT_QUALITY": 5}'::jsonb, 'PARTIAL', ARRAY['KB-01', 'KB-02', 'KB-03', 'KB-04', 'KB-05', 'KB-06', 'KB-07', 'KB-08', 'KB-09', 'KB-10']::text[], 'NOW()', 'NOW()');
INSERT INTO domain_scores (id, review_id, domain, score, rag_label, overall_readiness, executive_summary, compliant_areas, gap_areas, blocker_count, action_count, adr_count, domain_specific_scores, evidence_quality, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'business', 3, 'amber', 'APPROVE_WITH_CONDITIONS', 'The Bank EDMS solution aims to consolidate seven disparate document management systems into a single enterprise platform. The business case is well-articulated, highlighting significant operational inefficiencies and costs associated with the current fragmented approach. Key strengths include a defined domain model and operating model. However, critical areas such as Non-Functional Requirements (NFRs), detailed stakeholder analysis beyond a high-level map, and specific use case validation against customer needs require further elaboration. The current submission is partially compliant, necessitating conditions for approval.', ARRAY['Business Case: Problem statement and objectives are clear.', 'Business Scope: Use cases are identified.', 'Business Stakeholders: A high-level stakeholder map is provided.']::text[], ARRAY['BUS-F01: Business NFRs lack detail and quantitative targets.', 'BUS-F02: Stakeholder analysis is high-level and needs deeper engagement validation.', 'BUS-F03: Business use cases require validation against customer needs.']::text[], 0, 3, 0, NULL, 'PARTIAL', ARRAY['KB-02 | B-01', 'KB-03 | B-02', 'KB-04 | B-06', 'KB-09 | None']::text[], 'NOW()', 'NOW()');
INSERT INTO domain_scores (id, review_id, domain, score, rag_label, overall_readiness, executive_summary, compliant_areas, gap_areas, blocker_count, action_count, adr_count, domain_specific_scores, evidence_quality, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'integration', 3, 'amber', 'APPROVE_WITH_CONDITIONS', 'The Bank EDMS solution provides an initial integration catalogue and API catalog, demonstrating an understanding of integration principles. Key strengths include the documentation of inbound and outbound channels and adherence to some API design standards. However, critical gaps exist in the detailed design for security mechanisms, explicit adherence to standard protocols beyond REST, and a defined sunset policy for integrations. These areas require further architectural definition before full approval.', ARRAY['API_DESIGN_STANDARDS', 'IDEMPOTENCY']::text[], ARRAY['CATALOGUE_COMPLETENESS', 'INTEGRATION_SECURITY', 'NFR_COVERAGE']::text[], 0, 3, 1, '{"IDEMPOTENCY": 5, "NFR_COVERAGE": 3, "API_DESIGN_STANDARDS": 4, "INTEGRATION_SECURITY": 3, "CATALOGUE_COMPLETENESS": 3}'::jsonb, 'PARTIAL', ARRAY['KB-01 | GOV-01', 'KB-02 | INT-03', 'KB-03 | INT-01', 'KB-05 | INT-02', 'KB-06 | GOV-05', 'KB-08 | SEC-01']::text[], 'NOW()', 'NOW()');
INSERT INTO domain_scores (id, review_id, domain, score, rag_label, overall_readiness, executive_summary, compliant_areas, gap_areas, blocker_count, action_count, adr_count, domain_specific_scores, evidence_quality, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'data', 3, 'amber', 'APPROVE_WITH_CONDITIONS', 'The Bank EDMS data architecture leverages purpose-built AWS services (S3, RDS, OpenSearch) for document storage, metadata, and search, with clear separation of concerns. Data classification and lifecycle management are designed but pending formal DPO sign-off for key datasets. While the core architecture is robust, the lack of final governance approvals and detailed lifecycle policies presents a risk. The solution is approved with conditions to finalize these critical governance elements before go-live.', ARRAY['Data Architecture Overview (Artefact 1, Section 1)', 'Core Data Model Design (Artefact 1, Section 2)', 'Data Lifecycle Design (Artefact 1, Section 4)', 'Data Governance Framework (Artefact 1, Section 5)']::text[], ARRAY['DAT-F01: Pending DPO Sign-off for Data Classification', 'DAT-F02: Incomplete Data Lifecycle Policy Details']::text[], 0, 2, 0, NULL, 'PARTIAL', ARRAY['KB-01 | D-STD-03', 'KB-03 | D-02', 'KB-04 | D-03', 'KB-05 | D-STD-08', 'KB-06 | D-STD-01', 'KB-07 | D-10', 'KB-08 | D-STD-10']::text[], 'NOW()', 'NOW()');
INSERT INTO domain_scores (id, review_id, domain, score, rag_label, overall_readiness, executive_summary, compliant_areas, gap_areas, blocker_count, action_count, adr_count, domain_specific_scores, evidence_quality, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'infrastructure', 2, 'red', 'APPROVE_WITH_CONDITIONS', 'The Bank EDMS infrastructure is designed on AWS using EKS and provisioned entirely via AWS CDK TypeScript, adhering to IaC principles. It utilizes a two-region deployment for resilience. Key areas such as capacity planning, platform lifecycle, and interoperability are addressed to some extent. However, significant gaps exist in security controls, RBAC, PKI/encryption, and regulatory compliance, which require immediate attention. Operational aspects like detailed capacity planning and lifecycle management also need further refinement. The solution is approvable with conditions, pending resolution of critical security and compliance findings.', ARRAY['Infrastructure is 100% provisioned via AWS CDK TypeScript (IaC maturity).', 'Utilizes AWS EKS across two regions for High Availability and DR.', 'Istio service mesh for mTLS communication.']::text[], ARRAY['INF-F01: No detailed RBAC/IAM design provided.', 'INF-F02: Insufficient detail on PKI and encryption strategy.', 'INF-F03: Lacks a comprehensive regulatory compliance approach.', 'INF-F04: Capacity planning details are high-level and require further elaboration.', 'INF-F05: Platform lifecycle management lacks specific details on patching and upgrades.', 'INF-F06: No specific Authn/Authz design provided.']::text[], 0, 6, 1, NULL, 'PARTIAL', ARRAY['KB-01 | I-10', 'KB-02 | I-01', 'KB-03 | I-02', 'KB-04 | I-03', 'KB-05 | I-07', 'KB-06 | I-08', 'KB-07 | None', 'KB-08 | I-04', 'KB-09 | None', 'KB-10 | G-03']::text[], 'NOW()', 'NOW()');
INSERT INTO domain_scores (id, review_id, domain, score, rag_label, overall_readiness, executive_summary, compliant_areas, gap_areas, blocker_count, action_count, adr_count, domain_specific_scores, evidence_quality, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'devsecops', 3, 'amber', 'APPROVE_WITH_CONDITIONS', 'The Bank EDMS solution presents a robust DevSecOps architecture centered around GitHub Actions and ArgoCD, emphasizing shift-left security and GitOps principles. The CI/CD pipeline design is sound, with clear gate conditions and an environment-agnostic approach. Key strengths include the documented quality strategy and adherence to core DevSecOps principles. However, the branching strategy and detailed quality gate configurations need further elaboration to ensure comprehensive architectural clarity and enable development teams effectively. The current design is approvable with conditions, requiring specific actions to address these gaps.', ARRAY['DevSecOps Architecture Principles', 'CI/CD Pipeline Architecture', 'Deployment Design', 'Identity, Secrets & Config Management', 'Threat Model Architecture']::text[], ARRAY['DSO-F01: Branching Strategy', 'DSO-F02: Quality Strategy Details']::text[], 0, 2, 1, NULL, 'PARTIAL', ARRAY['KB-01 | Shift-Left Security', 'KB-02 | CI/CD Pipeline', 'KB-03 | Trunk-Based Development', 'KB-04 | Observability (Logs / Metrics / Traces)', 'KB-05 | Four Golden Signals', 'KB-06 | SLO / SLI / Error Budget', 'KB-07 | DORA Metrics']::text[], 'NOW()', 'NOW()');
INSERT INTO domain_scores (id, review_id, domain, score, rag_label, overall_readiness, executive_summary, compliant_areas, gap_areas, blocker_count, action_count, adr_count, domain_specific_scores, evidence_quality, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'nfr', 2, 'red', 'APPROVE_WITH_CONDITIONS', 'The Bank EDMS solution has a defined DR strategy based on a warm standby model with acceptable RTO/RPO targets. However, critical security gaps exist, specifically regarding IAM policies for service accounts, which must be remediated before production. Additionally, a VAPT plan is missing, which is a mandatory requirement for security assurance. These issues require immediate attention to ensure the solution meets enterprise NFR standards.', ARRAY['DR design meets RTO/RPO targets and warm standby model.', 'Security Controls Register identifies specific IAM policy gaps.']::text[], ARRAY['NFR-F01: Critical security gaps in service account IAM policies.', 'NFR-F02: Absence of a Vulnerability Assessment and Penetration Testing (VAPT) plan.']::text[], 1, 2, 0, '{"DR": {"gaps": [], "rag_label": "GREEN+", "rag_score": 4, "slo_target": "Defined RTO/RPO targets", "actual_evidenced": "RTO 4 hours, RPO 1 hour", "evidence_provided": ["DR design based on warm standby across two AWS regions", "Target RTO: 4 hours", "Target RPO: 1 hour", "DR runbook (INFRA-RB-001) authored and under review", "DR drill scheduled Q3 2026 before production go-live"], "is_mandatory_green": false, "mitigating_condition": ""}, "RBAC_IAM": {"gaps": ["Service accounts lack necessary LOB scope in IAM policies, posing a security risk."], "rag_label": "RED", "rag_score": 2, "slo_target": "All service accounts must have least-privilege IAM policies.", "actual_evidenced": "Identified 3 accounts missing scope, but not yet remediated.", "evidence_provided": ["ISSUE: 3 of 12 EDMS service accounts are missing LOB scope in their IAM policies."], "is_mandatory_green": true, "mitigating_condition": "Remediate IAM policies for all 3 service accounts to include LOB scope."}, "VAPT_EVIDENCE": {"gaps": ["No Vulnerability Assessment and Penetration Testing (VAPT) plan provided."], "rag_label": "AMBER", "rag_score": 3, "slo_target": "A VAPT plan must be in place before production go-live.", "actual_evidenced": "No VAPT plan evidenced.", "evidence_provided": [], "is_mandatory_green": true, "mitigating_condition": "Develop and submit a VAPT plan for review."}}'::jsonb, 'PARTIAL', ARRAY['KB-01 | None', 'KB-02 | G-03', 'KB-03 | G-02', 'KB-04 | G-09']::text[], 'NOW()', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'business', 'BUS-F03', 'BUS-F03', 'minor', 'Section 3, ''Business Use Cases,'' in ''03_EDMS_Business_Case_BRD.docx'' lists use cases, but there is no explicit evidence that these have been validated against actual customer needs or journey maps. This is a gap against KB-02 (Customer-Centricity).', 'Provide evidence or a plan to validate the listed business use cases against customer feedback, journey maps, or market research to confirm alignment with customer value.', 'BUSINESS_SCOPE', 'Business use cases require validation against customer needs.', 3, '03_EDMS_Business_Case_BRD.docx, Section 3. Business Use Cases', 'KB-02 | B-01 Customer-Centricity - Use cases must be validated against customer needs.', 'Risk that the EDMS may not fully address the needs of its end-users, leading to suboptimal adoption and value realization.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-02 | B-01']::text[], '03_EDMS_Business_Case_BRD.docx', 'KB-02 | B-01', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'application', 'APP-F01', 'APP-F01', 'minor', 'The HLD states a microservices-based platform on AWS but does not explicitly detail the adherence to Jakarta EE 9+ or Spring Boot 3+ as per KB-01. Specifics on dependency injection, persistence, transaction management, and security frameworks need to be confirmed.', 'The Solution Architect must provide a detailed breakdown of the chosen tech stack, explicitly confirming adherence to KB-01 requirements for all core application services, or propose a justified deviation.', 'TECH_STACK_COMPLIANCE', 'Tech Stack Compliance: Jakarta EE/Spring Boot adherence requires clarification', 3, 'Artefact 1: 04_EDMS_HLD_Application_Architecture.docx', 'Java Enterprise Edition (Jakarta EE) Application Standard (KB-01)', 'Potential for using non-standard or outdated frameworks, leading to increased technical debt, reduced maintainability, and potential security vulnerabilities.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-01']::text[], 'Artefact 1: 04_EDMS_HLD_Application_Architecture.docx', 'KB-01', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'application', 'APP-F02', 'APP-F02', 'minor', 'While the architecture is described as cloud-native and microservices-based, the HLD does not define specific scalability targets (e.g., TPS, concurrent users) or provide evidence of planned or actual performance testing, as required by KB-04.', 'The Solution Architect must document specific, measurable scalability targets for the EDMS and outline the plan for performance testing and validation, including expected outcomes.', 'SCALABILITY_PERFORMANCE', 'Scalability targets and validation evidence are missing', 3, 'Artefact 1: 04_EDMS_HLD_Application_Architecture.docx', 'Scalability (Application) (KB-04)', 'Risk of performance bottlenecks under load, inability to meet business demand, and inefficient resource utilization.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-04']::text[], 'Artefact 1: 04_EDMS_HLD_Application_Architecture.docx', 'KB-04', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'application', 'APP-F03', 'APP-F03', 'minor', 'The HLD does not provide details on how applicable compliance frameworks will be mapped to application-level controls or the approach to audit logging, as required by KB-03.', 'The Solution Architect must document the specific compliance frameworks relevant to EDMS and detail how application controls will address them, along with a clear strategy for comprehensive audit logging.', 'COMPLIANCE', 'Application compliance mapping and audit logging approach not detailed', 3, 'Artefact 1: 04_EDMS_HLD_Application_Architecture.docx', 'Compliance (Application) (KB-03)', 'Potential for non-compliance with regulatory requirements, leading to legal penalties, reputational damage, and audit failures. Inability to trace critical business events and user actions.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-03']::text[], 'Artefact 1: 04_EDMS_HLD_Application_Architecture.docx', 'KB-03', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'integration', 'INT-F01', 'INT-F01', 'minor', 'The SA submission indicates adherence to API design standards for the EDMS Document Management API v1, including documentation and versioning.', NULL, 'API_DESIGN_STANDARDS', 'API Design Standards Compliance Confirmed', 4, '05_EDMS_Integration_Catalogue_API_Catalog.docx', NULL, NULL, false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-05 | INT-02']::text[], '05_EDMS_Integration_Catalogue_API_Catalog.docx', 'KB-05 | INT-02', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'integration', 'INT-F02', 'INT-F02', 'minor', 'While the EDMS integration catalogue lists 4 inbound and 4 outbound channels, crucial metadata such as detailed data flows, specific NFRs for each, and owner information is not fully detailed for all entries.', 'Enhance the integration catalogue entries to include detailed data flows, specific NFRs, and assigned owners for all 8 integration channels.', 'CATALOGUE_COMPLETENESS', 'Incomplete Integration Catalogue Metadata for All Channels', 3, '05_EDMS_Integration_Catalogue_API_Catalog.docx', 'KB-02 | INT-03', 'Incomplete catalogue entries hinder impact analysis, dependency tracking, and overall integration landscape visibility.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-02 | INT-03']::text[], '05_EDMS_Integration_Catalogue_API_Catalog.docx', 'KB-02 | INT-03', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'integration', 'INT-F03', 'INT-F03', 'minor', 'The submission lacks explicit details on the authentication and authorization mechanisms used for integrations, and the adherence to standard protocols beyond REST is not fully detailed.', 'Provide detailed documentation on the authentication and authorization mechanisms for all integrations, and specify the standard protocols and data formats used for MQ and SFTP interfaces, aligning with KB-08 and KB-05.', 'INTEGRATION_SECURITY', 'Insufficient Detail on Security Mechanisms and Protocol Standards', 3, '05_EDMS_Integration_Catalogue_API_Catalog.docx', 'KB-08 | SEC-01, KB-05 | INT-02', 'Potential security vulnerabilities due to unconfirmed authentication/authorization, and interoperability issues if non-standard protocols/formats are used.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-08 | SEC-01', 'KB-05 | INT-02']::text[], '05_EDMS_Integration_Catalogue_API_Catalog.docx', 'KB-08 | SEC-01, KB-05 | INT-02', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'solution', 'SOL-F01', 'SOL-F01', 'minor', 'The solution states a targeted 25% TCO reduction but lacks a detailed breakdown of current vs. future state costs across development, maintenance, operations, infrastructure, and licensing. This level of detail is expected for significant strategic initiatives.', 'Provide a detailed TCO analysis comparing the aggregate cost of the seven current systems against the projected costs of the EDMS, broken down by category (development, operations, licensing, infrastructure, etc.).', 'ECONOMICS_TCO', 'Economic TCO analysis lacks detailed breakdown', 3, 'Business Drivers, Artefact 1 (Architecture Principles Standards)', 'KB-01: Economics - Total Cost of Ownership', 'Potential for underestimation of project costs or overestimation of savings, impacting financial planning and business case validity.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-01']::text[], 'Artefact 1: Architecture Principles Standards.docx (Section 7. Summary Assessment mentions TCO)', 'KB-01', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'solution', 'SOL-F02', 'SOL-F02', 'minor', 'Artefact 1 states compliance with technology standards but does not provide specific details on which standards are applied and how they are met by the EDMS components. While adherence is claimed, the evidence is high-level.', 'Augment the ''Technology Standards Compliance'' section in Artefact 1 or a related document to explicitly list the enterprise technology standards applicable to EDMS and map EDMS components to them.', 'ARCHITECTURE_PRINCIPLES_ADHERENCE', 'Adherence to Technology Standards is stated but lacks specific detail', 4, 'Artefact 1: Architecture Principles Standards.docx', 'KB-06: Engineer Solution With Strong Design Foundations - requires documented design decisions and adherence to patterns/standards.', 'Minor gap in documentation completeness; could lead to ambiguity for development teams regarding specific technology choices.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-06']::text[], 'Artefact 1: Architecture Principles Standards.docx', 'KB-06', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'business', 'BUS-F01', 'BUS-F01', 'minor', 'The Business NFR Register in ''03_EDMS_Business_Case_BRD.docx'' lists NFRs but lacks specific, measurable, achievable, relevant, and time-bound (SMART) targets. For example, security NFRs are descriptive (''User password specs / expiry / resets / locks'') without defined parameters.', 'Define specific, quantitative targets for all NFRs, including performance metrics (latency, throughput), security requirements (password complexity, lockout thresholds), and availability targets.', 'BUSINESS_NFRS', 'Business NFRs lack specific quantitative targets and detail.', 3, '03_EDMS_Business_Case_BRD.docx, Section 4. Business NFR Register', 'KB-04 | B-06 Data-Driven Decision Making - implies NFRs should be measurable.', 'Lack of defined NFRs can lead to under-designing for critical capabilities, resulting in performance issues, security vulnerabilities, or unmet business expectations.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-04 | B-06']::text[], '03_EDMS_Business_Case_BRD.docx', 'KB-04 | B-06', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'business', 'BUS-F02', 'BUS-F02', 'minor', 'Section 7, ''Stakeholder Map,'' in ''03_EDMS_Business_Case_BRD.docx'' provides a list of stakeholders but lacks depth regarding their specific needs, influence, and how their input has been incorporated into the design. KB-09 implies a need for deeper engagement.', 'Expand the stakeholder analysis to include their specific roles, influence, concerns, and how their feedback has shaped the EDMS design. Document key engagement activities.', 'BUSINESS_STAKEHOLDERS', 'Stakeholder analysis is high-level and lacks validation of engagement.', 3, '03_EDMS_Business_Case_BRD.docx, Section 7. Stakeholder Map', 'KB-09 | None - Architecture Review Taxonomy: Business Stakeholders requires detailed analysis and impact assessment.', 'Potential for overlooking critical requirements, resistance to adoption, and misalignment between the solution and business expectations.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-09 | None']::text[], '03_EDMS_Business_Case_BRD.docx', 'KB-09 | None', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'integration', 'INT-F04', 'INT-F04', 'minor', 'The solution architecture does not include a defined sunset policy for its integrations, which is a requirement for managing the integration lifecycle.', 'Develop and document a sunset policy for all 8 integration channels, including defined sunset dates, communication strategies, and migration support.', 'NFR_COVERAGE', 'Missing Sunset Policy for Integrations', 3, '05_EDMS_Integration_Catalogue_API_Catalog.docx', 'KB-06 | GOV-05', 'Risk of accumulating technical debt, increased maintenance burden, and lack of clarity for consumers regarding the longevity of integration services.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-06 | GOV-05']::text[], '05_EDMS_Integration_Catalogue_API_Catalog.docx', 'KB-06 | GOV-05', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'data', 'DAT-F01', 'DAT-F01', 'minor', 'The Data Classification Register indicates pending DPO sign-off for several critical datasets (Retail Banking KYC, FCA Compliance filings, Risk Model docs) due to ongoing reviews of PII disposal and S3 bucket provisioning.', 'Expedite DPO review and approval for the pending data classifications, ensuring remediation of identified issues (e.g., UK S3 bucket provisioning).', 'DATA_CLASSIFICATION', 'Pending DPO Sign-off for Data Classification', 3, '08_EDMS_Data_Architecture.docx, Section 3', 'D-STD-03 Data Classification and Handling Standard', 'Potential non-compliance with data handling regulations and internal policies, risk of inappropriate data exposure or processing for sensitive data.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-01 | D-STD-03']::text[], '08_EDMS_Data_Architecture.docx, Section 3', 'KB-01 | D-STD-03', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'data', 'DAT-F02', 'DAT-F02', 'minor', 'While a Retention Policy Engine Design is mentioned, the Artefact 1, Section 4.2 lacks specific details on the defined retention periods, archival strategies, and disposal mechanisms for different data classifications.', 'Detail the data lifecycle policies, including specific retention periods, archival procedures, and secure disposal methods, aligned with data classifications.', 'DATA_LIFECYCLE', 'Incomplete Data Lifecycle Policy Details', 3, '08_EDMS_Data_Architecture.docx, Section 4.2', 'D-STD-03 Data Classification and Handling Standard', 'Inconsistent application of data retention and disposal, potential for data to be held longer than necessary (compliance/cost risk) or disposed of prematurely (business risk).', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-01 | D-STD-03']::text[], '08_EDMS_Data_Architecture.docx, Section 4.2', 'KB-01 | D-STD-03', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'infrastructure', 'INF-F01', 'G-06', 'major', 'The submission lacks a detailed design for Role-Based Access Control (RBAC) and Identity and Access Management (IAM) for the EDMS infrastructure. This is a critical gap for secure access management.', 'Provide a detailed RBAC/IAM design document outlining roles, permissions, and access policies for all infrastructure components and services.', 'RBAC_IAM', 'RBAC/IAM design is absent in the submission', 2, '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx, Section 1.7', 'Enterprise Security Standards, RBAC/IAM Design Principles', 'Potential for unauthorized access, privilege escalation, and security breaches due to undefined access controls.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-09 | None']::text[], '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx', 'KB-09 | None - Architecture Review Taxonomy (RBAC/IAM)', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'infrastructure', 'INF-F02', 'G-06', 'major', 'While mTLS is mentioned for pod-to-pod communication via Istio, the overall strategy for Public Key Infrastructure (PKI) and data encryption (at-rest and in-transit beyond mTLS) is not sufficiently detailed.', 'Document the comprehensive PKI strategy, including certificate lifecycle management, and the encryption approach for data at rest and in transit across all relevant infrastructure components.', 'PKI_ENCRYPTION', 'PKI and encryption strategy lacks sufficient detail', 2, '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx, Section 1.1', 'Enterprise Cryptography Standards, Data Protection Policies', 'Potential for data exposure, compliance violations, and security vulnerabilities if encryption and PKI are not robustly designed and managed.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-09 | None']::text[], '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx', 'KB-09 | None - Architecture Review Taxonomy (PKI/Encryption)', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'infrastructure', 'INF-F03', 'B-02', 'major', 'The submission does not clearly articulate how the infrastructure design meets specific regulatory compliance requirements relevant to a banking system.', 'Provide a dedicated section or document detailing the regulatory compliance strategy, mapping infrastructure controls to specific regulatory requirements.', 'REGULATORY_COMPLIANCE', 'Regulatory compliance approach is not clearly defined', 2, '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx', 'Regulatory Compliance Mandates for Financial Institutions', 'Risk of non-compliance, leading to significant fines, legal repercussions, and reputational damage.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-09 | None']::text[], '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx', 'KB-09 | None - Architecture Review Taxonomy (Regulatory Compliance)', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'infrastructure', 'INF-F04', 'G-04', 'minor', 'The capacity plan (Section 5.2) provides LOB-specific estimates for Year 1 but lacks detail on auto-scaling configurations, headroom calculations, and periodic review processes.', 'Elaborate on auto-scaling configurations, define headroom targets, and outline the process for regular capacity planning reviews and adjustments.', 'CAPACITY_PLANNING', 'Capacity planning details are high-level', 3, '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx, Section 5.2', 'KB-02 | I-01 Scalability (Infrastructure)', 'Potential for service degradation or over-provisioning if scaling is not adequately configured or monitored.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-02 | I-01']::text[], '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx', 'KB-02 | I-01', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'infrastructure', 'INF-F05', 'G-09', 'minor', 'Section 6 ''Platform Lifecycle Register'' is present but lacks specific details on how patching, upgrades (EKS, Istio, OS), and end-of-life management will be handled.', 'Detail the processes and automation for patching, upgrading EKS, Istio, and underlying OS images, including testing and rollback procedures.', 'PLATFORM_LIFECYCLE', 'Platform lifecycle management lacks specific details', 3, '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx, Section 6', 'KB-04 | I-03 Standardization (related to golden images and updates)', 'Security vulnerabilities due to unpatched systems, instability from outdated components, and potential operational disruption.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-04 | I-03']::text[], '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx', 'KB-04 | I-03', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'infrastructure', 'INF-F06', 'G-06', 'major', 'The submission does not include a design for how users and services will authenticate to and be authorized by the infrastructure components.', 'Provide a clear design for authentication (e.g., SSO, OIDC) and authorization mechanisms for both human users and service accounts interacting with the infrastructure.', 'AUTHN_AUTHZ', 'Authentication and Authorization (Authn/Authz) design is missing', 2, '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx', 'Enterprise Authentication & Authorization Standards', 'Risk of unauthorized access to infrastructure and services, leading to potential data breaches or system compromise.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-09 | None']::text[], '09_EDMS_Infrastructure_Capacity_Platform_Lifecycle.docx', 'KB-09 | None - Architecture Review Taxonomy (Authn/Authz)', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'devsecops', 'DSO-F01', 'DSO-F01', 'minor', 'The document mentions a branching strategy but provides no details on its implementation or adherence to patterns like Trunk-Based Development, which is crucial for CI/CD.', 'Document the chosen branching strategy, including details on branch naming, merge process, and how it supports CI/CD and shift-left security.', 'BRANCHING_STRATEGY', 'Branching Strategy Lacks Detail', 3, '10_EDMS_Engineering_DevSecOps_Pipeline.docx, Section 3', 'Trunk-Based Development (KB-03) principles require clear definition and adherence.', 'Potential for integration issues, delayed feedback loops, and reduced CI/CD efficiency.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-03 | Trunk-Based Development']::text[], '10_EDMS_Engineering_DevSecOps_Pipeline.docx', 'KB-03 | Trunk-Based Development', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'devsecops', 'DSO-F02', 'DSO-F02', 'minor', 'The ''Quality Strategy'' section outlines the intent but lacks specific details on the configuration and thresholds for the quality gates within the CI/CD pipeline.', 'Detail the specific quality gates, their associated thresholds (e.g., SAST vulnerability severity, minimum test coverage), and the conditions under which they block progression.', 'CICD_PIPELINE_QUALITY', 'Quality Strategy Lacks Specificity on Gate Configurations', 3, '10_EDMS_Engineering_DevSecOps_Pipeline.docx, Section 6', 'Effective CI/CD pipelines require clearly defined and configurable quality gates (KB-02).', 'Ambiguity in quality expectations can lead to inconsistent quality, potential security risks, and delays in deployment.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-02 | CI/CD Pipeline']::text[], '10_EDMS_Engineering_DevSecOps_Pipeline.docx', 'KB-02 | CI/CD Pipeline', 'NOW()');
INSERT INTO findings (id, review_id, domain, finding_id, principle_id, severity, finding, recommendation, check_category, title, rag_score, evidence_source, standard_violated, impact, is_blocker, is_resolved, links_to_action_ids, links_to_adr_id, waiver_eligible, kb_reference, artifact_ref, kb_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'nfr', 'NFR-F02', 'NFR-F02', 'minor', 'The solution lacks a documented Vulnerability Assessment and Penetration Testing (VAPT) plan, which is a mandatory requirement for security assurance before production deployment.', 'Develop and submit a comprehensive VAPT plan, outlining scope, methodology, and timeline, for review and approval.', 'VAPT_EVIDENCE', 'Vulnerability Assessment and Penetration Testing (VAPT) Plan is Missing', 3, 'No VAPT plan found in submitted artifacts.', 'Enterprise Security Testing Policy §3.1 - Mandatory VAPT for Production Systems', 'Inability to proactively identify and address security vulnerabilities before deployment, increasing the risk of exploitation.', false, false, ARRAY[]::text[], NULL, false, ARRAY['KB-01 | None']::text[], 'No VAPT plan found in submitted artifacts.', 'KB-01 | None', 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'APP-REC-02', 'APP', 'low', 'Consider Ambassador Pattern for Legacy Integrations', 'If EDMS needs to integrate with legacy systems that lack modern resilience features, the Ambassador pattern can provide an externalized solution.', 'Ambassador (KB-07)', 'Improves resilience of integrations without modifying the legacy systems.', 'Evaluate potential integration points where this pattern could be applied to enhance stability.', NULL, NULL, true, ARRAY['KB-07']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'SOL-REC-01', 'SOL', 'medium', 'Enhance Economic TCO Analysis with Detailed Cost Breakdown', 'While a 25% TCO reduction is modeled, a more granular breakdown of development, maintenance, operational, infrastructure, and licensing costs for the EDMS, compared to the aggregate of the seven current systems, would provide greater financial transparency and support for the investment.', 'KB-01: Economics - Total Cost of Ownership', 'Improved financial justification and clearer understanding of cost drivers for the EDMS.', 'Develop a detailed TCO model comparing current state aggregate costs with projected EDMS costs across key categories.', 'SOL-F01', NULL, true, ARRAY['KB-01']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'SOL-REC-02', 'SOL', 'low', 'Document Specific Technology Standards Compliance in Detail', 'The ''Architecture Principles Standards'' document mentions compliance with technology standards but lacks specific details on which standards are applied and how. Explicitly mapping EDMS components to relevant enterprise technology standards (e.g., database, messaging, API gateway standards) would strengthen the design documentation.', 'KB-06: Engineer Solution With Strong Design Foundations', 'Clearer assurance of adherence to enterprise technology direction and reduced ambiguity for development teams.', 'Create a matrix or add a section to the ''Architecture Principles Standards'' document detailing EDMS components and their alignment with specific enterprise technology standards.', 'SOL-F02', NULL, true, ARRAY['KB-06']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'SOL-REC-03', 'SOL', 'low', 'Consider Implementing a Composable Architecture for Future Flexibility', 'Given the goal of consolidating diverse document types and LOB requirements, exploring a more composable architecture for EDMS (as per KB-08) could offer greater flexibility in adapting to future LOB needs or regulatory changes by treating document management functions as independent, reusable components.', 'KB-08: Composable Architecture', 'Increased agility in adapting the EDMS to evolving business requirements and regulatory landscapes.', 'Identify potential modular components within the EDMS design (e.g., ingestion, search, retention policy engine) that could be independently developed and composed.', NULL, NULL, true, ARRAY['KB-08']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'BUS-REC-01', 'BUS', 'medium', 'Enhance Business NFRs with Quantitative Targets and Baselines', 'The current NFRs are descriptive; adding quantitative targets and baselines will provide measurable goals for the EDMS.', 'KB-04 | B-06 Data-Driven Decision Making', 'Ensures clarity on performance, security, and availability expectations, enabling better design and testing.', 'Define specific SLOs for latency, throughput, uptime, and security compliance for each NFR category.', 'BUS-F01', NULL, true, ARRAY['KB-04 | B-06']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'BUS-REC-02', 'BUS', 'medium', 'Conduct Deeper Stakeholder Analysis and Engagement Validation', 'A more detailed stakeholder analysis, including their specific needs and influence, will ensure broader buy-in and better alignment.', 'KB-09 | None Architecture Review Taxonomy - Business Stakeholders', 'Reduces risk of scope creep, ensures all critical perspectives are considered, and improves adoption.', 'Map stakeholders by influence and interest, and document how their feedback was incorporated into the design.', 'BUS-F02', NULL, true, ARRAY['KB-09 | None']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'BUS-REC-03', 'BUS', 'high', 'Validate Business Use Cases with Customer Journey Mapping', 'Explicitly linking use cases to customer journeys and needs ensures the EDMS delivers tangible customer value.', 'KB-02 | B-01 Customer-Centricity', 'Ensures the solution directly addresses customer pain points and enhances their experience, leading to higher adoption and satisfaction.', 'Create or reference customer journey maps that illustrate how the EDMS will be used and the value it provides at each touchpoint.', 'BUS-F03', NULL, true, ARRAY['KB-02 | B-01']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'APP-REC-01', 'APP', 'medium', 'Adopt Plugin Architecture for Extensibility', 'The EDMS could benefit from a plugin architecture to allow for independent development and deployment of new document types or workflows.', 'Plugin Architecture (KB-08)', 'Enhances modularity, reduces core system modification risk, and speeds up feature delivery.', 'Define clear extension points and APIs in the core EDMS for future plugin development.', NULL, NULL, true, ARRAY['KB-08']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'APP-REC-03', 'APP', 'medium', 'Establish API Versioning Strategy', 'To ensure backward compatibility and manage evolution of EDMS APIs, a clear versioning strategy is essential.', 'Interoperability (KB-06)', 'Prevents breaking changes for consumers and allows for controlled rollout of new API versions.', 'Define versioning approach (e.g., URL path, header) and communicate it in API documentation.', 'APP-F01', NULL, true, ARRAY['KB-06']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INT-REC-01', 'INT', 'medium', 'Adopt a Centralized API Gateway for All Integrations', 'While the solution mentions API Gateway, explicitly routing all cross-domain and external integrations through it ensures consistent security, monitoring, and policy enforcement as per enterprise standards.', 'KB-03 | INT-01', 'Enhanced security posture, simplified management, and consistent application of policies across all integrations.', 'Review all inbound and outbound integration points to ensure they are configured to use the enterprise API Gateway.', 'INT-F02', NULL, true, ARRAY['KB-03 | INT-01']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INT-REC-02', 'INT', 'low', 'Standardize Non-REST Integration Protocols and Formats', 'The solution mentions MQ and SFTP interfaces. Standardizing these with enterprise-approved formats (e.g., Avro, JSON Schema) and protocols will improve interoperability and reduce technical debt.', 'KB-05 | INT-02', 'Improved interoperability, maintainability, and reduced risk of using proprietary or outdated integration methods.', 'Document the specific message schemas and protocols used for MQ and SFTP interfaces and ensure they align with KB-05 standards.', 'INT-F03', NULL, true, ARRAY['KB-05 | INT-02']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INT-REC-03', 'INT', 'medium', 'Establish Formal Sunset Policy for Integrations', 'A defined sunset policy is crucial for managing the integration lifecycle, preventing technical debt, and ensuring timely migration or decommissioning of integrations.', 'KB-06 | GOV-05', 'Proactive management of integration lifecycle, reduced maintenance overhead, and clear communication for consumers regarding integration longevity.', 'Define sunset dates, communication plans, and migration strategies for all 8 integration points (4 inbound, 4 outbound).', 'INT-F03', NULL, true, ARRAY['KB-06 | GOV-05']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'DAT-REC-01', 'DAT', 'medium', 'Implement Automated Data Quality Monitoring for Metadata', 'While binary storage is handled by S3, ensuring the quality and consistency of metadata synchronized across RDS and OpenSearch is crucial for search and lifecycle management.', 'D-STD-08 Data Quality Monitoring and Remediation Standard', 'Proactively identifies and resolves metadata inconsistencies, improving search accuracy and lifecycle policy enforcement.', 'Define data quality rules for metadata fields (e.g., completeness of classification tags, validity of dates) and integrate them into the synchronization process.', NULL, NULL, true, ARRAY['KB-05 | D-STD-08']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'DAT-REC-02', 'DAT', 'low', 'Consider Data Mesh Principles for Future Evolution', 'As the EDMS grows and potentially integrates with other enterprise systems, adopting a data mesh approach could decentralize data ownership and improve agility.', 'Data Mesh (KB-02)', 'Enhances scalability, domain autonomy, and data product discoverability.', 'Explore domain-oriented data product thinking for metadata and document access patterns.', NULL, NULL, true, ARRAY['KB-02 | None']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INF-REC-01', 'INF', 'high', 'Implement granular cost allocation tagging for all AWS resources', 'Effective cost management and FinOps require precise tagging to attribute costs to specific services, teams, or projects.', 'KB-08 | I-04 Cost Efficiency', 'Improved cost visibility, accurate chargebacks, and identification of optimization opportunities.', 'Define a mandatory tagging strategy and enforce it via AWS Config or CDK policies.', NULL, NULL, true, ARRAY['KB-08 | I-04']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INF-REC-02', 'INF', 'medium', 'Adopt Chaos Engineering practices for resilience validation', 'While resilience is designed, proactive testing through chaos engineering can uncover latent weaknesses before they impact production.', 'KB-06 | I-08 Resilience', 'Increased confidence in the system''s ability to withstand failures and faster identification of resilience gaps.', 'Start with controlled experiments targeting specific failure scenarios (e.g., AZ outage, pod failures).', NULL, NULL, true, ARRAY['KB-06 | I-08']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INF-REC-03', 'INF', 'low', 'Establish a formal automation maturity roadmap for infrastructure operations', 'A roadmap will guide the continuous improvement of automation, ensuring consistent progress towards reducing manual toil and increasing operational efficiency.', 'KB-05 | I-07 Automation', 'Systematic enhancement of operational efficiency, reduced human error, and improved auditability.', 'Identify key manual processes and prioritize them for automation based on frequency, risk, and effort.', NULL, NULL, true, ARRAY['KB-05 | I-07']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'DSO-REC-01', 'DSO', 'medium', 'Enhance Observability by Integrating Distributed Tracing', 'While the solution outlines a quality strategy, explicit mention of distributed tracing would further improve the ability to diagnose issues across microservices, aligning with modern observability best practices.', 'KB-04 | Observability (Logs / Metrics / Traces)', 'Improved root cause analysis and performance monitoring across distributed systems.', 'Incorporate a distributed tracing solution (e.g., Jaeger, Zipkin) into the CI/CD pipeline and ensure services emit trace data.', NULL, NULL, true, ARRAY['KB-04 | Observability (Logs / Metrics / Traces)']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'DSO-REC-02', 'DSO', 'low', 'Adopt DORA Metrics for Continuous Improvement', 'The solution''s CI/CD and quality gates are well-defined, but explicitly tracking DORA metrics can provide data-driven insights into delivery performance and identify areas for optimization.', 'KB-07 | DORA Metrics', 'Data-driven insights into deployment frequency, lead time, change failure rate, and MTTR to optimize the software delivery process.', 'Integrate tooling to automatically capture and visualize DORA metrics within the CI/CD platform.', NULL, NULL, true, ARRAY['KB-07 | DORA Metrics']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'DSO-REC-03', 'DSO', 'medium', 'Formalize SLOs and Error Budgets for Quality Gates', 'While quality gates are defined, formalizing them as Service Level Objectives (SLOs) with associated error budgets would provide a more objective and data-driven approach to managing releases and reliability.', 'KB-06 | SLO / SLI / Error Budget', 'Objective, data-driven approach to managing reliability and release velocity, enabling informed trade-offs.', 'Define specific SLIs for key quality gates and establish error budgets that influence release decisions.', 'DSO-F02', NULL, true, ARRAY['KB-06 | SLO / SLI / Error Budget']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'NFR-REC-01', 'NFR', 'high', 'Enhance DR Strategy with Regular Testing and Automation', 'While the DR strategy is defined, regular, automated DR drills are crucial to validate its effectiveness and ensure RTO/RPO targets can be met under real-world conditions.', 'Disaster Recovery Best Practices', 'Increased confidence in business continuity, reduced recovery time in a disaster scenario, and identification of potential DR plan flaws.', 'Schedule automated DR drills quarterly and document the outcomes.', NULL, NULL, true, ARRAY['KB-01 | None']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'NFR-REC-02', 'NFR', 'medium', 'Implement Comprehensive Observability for Performance and Reliability', 'To proactively manage performance and reliability, the EDMS solution should incorporate robust logging, metrics, and tracing capabilities.', 'Observability Patterns', 'Improved troubleshooting, faster incident response, better capacity planning, and enhanced end-user experience.', 'Define key performance indicators (KPIs) and implement monitoring dashboards for critical system components.', NULL, NULL, true, ARRAY['KB-01 | None']::text[], 'NOW()');
INSERT INTO recommendations (id, review_id, recommendation_id, domain, priority, title, rationale, approved_pattern_ref, benefit, implementation_hint, applies_to_finding_id, applies_to_adr_id, is_agent_generated, kb_source_ref, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'NFR-REC-03', 'NFR', 'low', 'Consider a Phased Approach for Future Enhancements', 'Applying the ''Bias for Action'' principle, future enhancements should be delivered in manageable increments, allowing for faster feedback and reducing the risk of large, complex deployments.', 'KB-03 | G-02 - Bias For Action', 'Faster time-to-market for new features, reduced development risk, and greater agility in responding to business needs.', 'Decompose future feature requests into smaller, deliverable user stories with clear acceptance criteria.', NULL, NULL, true, ARRAY['KB-03 | G-02']::text[], 'NOW()');
