INSERT INTO nfr_scorecard (id, review_id, nfr_category, rag_score, rag_label, evidence_provided, gaps, mitigating_condition, slo_target, actual_evidenced, is_mandatory_green, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'rbac_iam', 2, 'red', ARRAY['ISSUE: 3 of 12 EDMS service accounts are missing LOB scope in their IAM policies.']::text[], ARRAY['Service accounts lack necessary LOB scope in IAM policies, posing a security risk.']::text[], 'Remediate IAM policies for all 3 service accounts to include LOB scope.', 'All service accounts must have least-privilege IAM policies.', 'Identified 3 accounts missing scope, but not yet remediated.', false, 'NOW()');
