INSERT INTO nfr_scorecard (id, review_id, nfr_category, rag_score, rag_label, evidence_provided, gaps, mitigating_condition, slo_target, actual_evidenced, is_mandatory_green, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'authn_authz', 2, 'red', ARRAY['07_EDMS_NFR_HA_DR_Security_Controls.docx mentions: ''ISSUE: 3 of 12 EDMS service accounts are missing LOB scope in their IAM policies. These must be remediated before production. See Action ACT-02.''']::text[], ARRAY['Incomplete IAM policy scope for service accounts.']::text[], 'Remediate IAM policies to include full LOB scope.', 'All service accounts must have precisely defined IAM policies with appropriate scope.', 'Partial evidence, with identified gaps.', false, 'NOW()');
INSERT INTO nfr_scorecard (id, review_id, nfr_category, rag_score, rag_label, evidence_provided, gaps, mitigating_condition, slo_target, actual_evidenced, is_mandatory_green, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'pki_encryption', 2, 'red', ARRAY[]::text[], ARRAY['No documented design for encryption at rest and in transit.', 'No explicit design for PKI and certificate management.']::text[], 'Provide detailed design for encryption at rest/in transit and PKI/certificate management.', 'Data encrypted at rest and in transit using approved algorithms; robust PKI management.', 'Absent.', false, 'NOW()');
INSERT INTO nfr_scorecard (id, review_id, nfr_category, rag_score, rag_label, evidence_provided, gaps, mitigating_condition, slo_target, actual_evidenced, is_mandatory_green, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'regulatory_compliance', 4, 'green+', ARRAY['The DR design and security controls document implies adherence to general compliance requirements by addressing RTO/RPO and security issues.']::text[], ARRAY[]::text[], NULL, 'Compliance with all relevant financial regulations and data privacy laws.', 'Sufficient for this stage, pending resolution of other security findings.', false, 'NOW()');
INSERT INTO nfr_scorecard (id, review_id, nfr_category, rag_score, rag_label, evidence_provided, gaps, mitigating_condition, slo_target, actual_evidenced, is_mandatory_green, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'scalability_performance', 2, 'red', ARRAY[]::text[], ARRAY['Absence of detailed design for scalability and performance, including capacity planning and load balancing strategies.']::text[], 'Provide a detailed design for scalability and performance.', 'System must meet defined performance and scalability SLOs under expected load.', 'Absent.', false, 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'SOL-ACT-01', 'SOL', 'documentation', 'Provide detailed TCO analysis for EDMS', 'Develop and submit a detailed Total Cost of Ownership (TCO) analysis for the EDMS, comparing the aggregate costs of the seven current systems with the projected costs of the EDMS. The analysis should break down costs by category (development, operations, licensing, infrastructure, etc.) and provide supporting data for the claimed 25% reduction.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of submitted TCO analysis document.', false, 'SOL-F01', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'BUS-ACT-01', 'BUS', 'amber_condition', 'Define quantitative targets for all Business NFRs.', 'Update Section 4 of the ''03_EDMS_Business_Case_BRD.docx'' to include specific, measurable, achievable, relevant, and time-bound (SMART) targets for all listed NFRs, including performance, security, and availability.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated ''03_EDMS_Business_Case_BRD.docx'' by Enterprise Architecture.', true, 'BUS-F01', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'BUS-ACT-02', 'BUS', 'amber_condition', 'Enhance Stakeholder analysis with engagement details.', 'Expand Section 7 of the ''03_EDMS_Business_Case_BRD.docx'' to detail stakeholder roles, influence, specific needs, and documented engagement activities. This should include how feedback has been incorporated into the EDMS design.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated ''03_EDMS_Business_Case_BRD.docx'' by Enterprise Architecture.', true, 'BUS-F02', NULL, NULL, 'MEDIUM', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'BUS-ACT-03', 'BUS', 'amber_condition', 'Validate Business Use Cases against customer needs.', 'Update Section 3 of the ''03_EDMS_Business_Case_BRD.docx'' to provide evidence or a plan for validating the listed business use cases against customer journeys, feedback, or market research. Document the alignment with customer value.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated ''03_EDMS_Business_Case_BRD.docx'' by Enterprise Architecture.', true, 'BUS-F03', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'APP-ACT-01', 'APP', 'amber_condition', 'Clarify EDMS Tech Stack Compliance with KB-01', 'Provide a detailed breakdown of the EDMS tech stack, explicitly confirming adherence to KB-01 requirements (Jakarta EE 9+/Spring Boot 3+, CDI/Spring IoC, JPA, JTA/@Transactional, Jakarta EE Security/Spring Security) for all core application services. If deviations are necessary, provide documented rationale.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated documentation or a supplementary artifact detailing the tech stack and compliance.', true, 'APP-F01', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'APP-ACT-02', 'APP', 'amber_condition', 'Define and Validate EDMS Scalability Targets', 'Document specific, measurable scalability targets for the EDMS (e.g., Transactions Per Second, concurrent users, data volume growth) and outline the plan for performance testing and validation, including expected outcomes and any required autoscaling policies.', 'open', 'solution_architect', 60, 'solution_architect', 'WITHIN_60_DAYS', 'Review of updated HLD or a dedicated scalability/performance plan document.', true, 'APP-F02', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'APP-ACT-03', 'APP', 'amber_condition', 'Document EDMS Compliance Mapping and Audit Logging Strategy', 'Detail the specific compliance frameworks relevant to EDMS and document how application controls will address them. Provide a clear strategy for comprehensive audit logging, specifying what events will be captured and how.', 'open', 'solution_architect', 60, 'solution_architect', 'WITHIN_60_DAYS', 'Review of updated HLD or a dedicated compliance and audit logging strategy document.', true, 'APP-F03', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INT-ACT-01', 'INT', 'amber_condition', 'Complete Integration Catalogue Metadata', 'Update the integration catalogue in ''05_EDMS_Integration_Catalogue_API_Catalog.docx'' to include detailed data flows, specific NFRs, and assigned owners for all 8 integration channels.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated ''05_EDMS_Integration_Catalogue_API_Catalog.docx'' or equivalent catalogue.', false, 'INT-F02', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INT-ACT-02', 'INT', 'amber_condition', 'Document Integration Security Mechanisms and Protocol Standards', 'Provide detailed documentation within ''05_EDMS_Integration_Catalogue_API_Catalog.docx'' or a linked artifact, specifying the authentication and authorization mechanisms (per KB-08) and the standard protocols/formats (per KB-05) for all integrations, especially MQ and SFTP.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated documentation confirming adherence to KB-08 and KB-05 standards.', false, 'INT-F03', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INT-ACT-03', 'INT', 'amber_condition', 'Define and Document Integration Sunset Policy', 'Develop and document a formal sunset policy for all 8 integration channels, including sunset dates, communication plans, and migration support strategies, as required by KB-06.', 'open', 'solution_architect', 60, 'solution_architect', 'WITHIN_60_DAYS', 'Review of documented sunset policy for all integrations.', false, 'INT-F04', NULL, NULL, 'MEDIUM', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'DAT-ACT-01', 'DAT', 'amber_condition', 'Expedite DPO Sign-off for Pending Data Classifications', 'Obtain formal Data Protection Officer (DPO) sign-off for the pending data classifications identified in Artefact 1, Section 3 (Retail Banking KYC, FCA Compliance filings, Risk Model docs). Address any outstanding issues raised during the review, such as UK S3 bucket provisioning.', 'open', 'solution_architect', 90, 'solution_architect', 'PRE_GO_LIVE', 'Updated Artefact 1, Section 3 showing DPO sign-off, or equivalent confirmation document.', true, 'DAT-F01', NULL, NULL, 'HIGH', 'NOW()');
