INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INF-ACT-03', 'INF', 'amber_condition', 'Define and document regulatory compliance approach', 'Provide a dedicated section or document detailing the regulatory compliance strategy, mapping infrastructure controls to specific regulatory requirements.', 'open', 'solution_architect', 60, 'solution_architect', 'PRE_GO_LIVE', 'Review of the documented regulatory compliance strategy.', true, 'INF-F03', NULL, NULL, 'CRITICAL', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INF-ACT-04', 'INF', 'amber_condition', 'Elaborate on capacity planning details', 'Provide further details on auto-scaling configurations, define headroom targets, and outline the process for regular capacity planning reviews and adjustments.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated capacity planning documentation.', false, 'INF-F04', NULL, NULL, 'MEDIUM', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INF-ACT-05', 'INF', 'amber_condition', 'Detail platform lifecycle management processes', 'Detail the processes and automation for patching, upgrading EKS, Istio, and underlying OS images, including testing and rollback procedures.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated platform lifecycle management documentation.', false, 'INF-F05', NULL, NULL, 'MEDIUM', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'INF-ACT-06', 'INF', 'amber_condition', 'Provide Authn/Authz design for infrastructure', 'Develop and submit a clear design for authentication (e.g., SSO, OIDC) and authorization mechanisms for both human users and service accounts interacting with the infrastructure.', 'open', 'solution_architect', 60, 'solution_architect', 'PRE_GO_LIVE', 'Review of the submitted Authn/Authz design document.', true, 'INF-F06', NULL, NULL, 'CRITICAL', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'DSO-ACT-01', 'DSO', 'documentation', 'Document the EDMS Branching Strategy', 'Provide a detailed description of the branching strategy for the EDMS project, including branch lifecycle, merge policies, and how it supports CI/CD and shift-left security.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated ''10_EDMS_Engineering_DevSecOps_Pipeline.docx'' or a linked document detailing the branching strategy.', false, 'DSO-F01', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'DSO-ACT-02', 'DSO', 'documentation', 'Specify Quality Gate Configurations', 'Elaborate on the ''Quality Strategy'' section in ''10_EDMS_Engineering_DevSecOps_Pipeline.docx'' by detailing the specific quality gates, their thresholds (e.g., SAST severity, test coverage percentage), and the conditions that cause them to block pipeline progression.', 'open', 'solution_architect', 30, 'solution_architect', 'WITHIN_30_DAYS', 'Review of updated ''10_EDMS_Engineering_DevSecOps_Pipeline.docx'' or a linked document detailing the specific quality gate configurations.', false, 'DSO-F02', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'NFR-ACT-01', 'NFR', 'blocker_resolution', 'Remediate EDMS Service Account IAM Policies', 'Update the IAM policies for the 3 identified EDMS service accounts to include the necessary LOB scope, adhering to the principle of least privilege. Provide evidence of the updated policies.', 'open', 'solution_architect', 60, 'solution_architect', 'PRE_GO_LIVE', 'Review of updated IAM policies and confirmation via a security scan or audit report.', true, 'NFR-F01', 'NFR-BLK-01', NULL, 'CRITICAL', 'NOW()');
INSERT INTO actions (id, review_id, action_id, domain, action_type, title, action_text, status, owner_role, due_days, proposed_owner, proposed_due_date, verification_method, is_conditional_approval_gate, links_to_finding_id, links_to_blocker_id, links_to_adr_id, priority, created_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'NFR-ACT-02', 'NFR', 'amber_condition', 'Develop and Submit VAPT Plan for EDMS', 'Create a detailed Vulnerability Assessment and Penetration Testing (VAPT) plan for the EDMS solution, including scope, methodology, timelines, and responsible parties. Submit the plan for ARB review and approval.', 'open', 'solution_architect', 60, 'solution_architect', 'PRE_GO_LIVE', 'Review and approval of the submitted VAPT plan by the Enterprise Architecture and Security teams.', true, 'NFR-F02', NULL, NULL, 'HIGH', 'NOW()');
INSERT INTO adrs (id, review_id, adr_id, domain, adr_type, title, decision, rationale, context, owner, proposed_owner, target_date, proposed_target_date, waiver_expiry_date, status, options_considered, mitigations, links_to_finding_ids, links_to_action_ids, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'ADR-INT-01', 'INT', 'new_decision', 'Decision: Use of API Gateway for External and Cross-Domain Integrations', 'All external-facing APIs and cross-domain integrations for the Bank EDMS solution will be exposed and mediated through the enterprise API Gateway. Direct peer-to-peer communication is prohibited.', 'This decision aligns with the enterprise standard INT-01 (API Gateway Mediation) which mandates routing integrations through the gateway for centralized control, security, monitoring, and governance.', 'The Bank EDMS solution involves multiple integration points. A decision was needed on how these integrations would be exposed and managed to ensure compliance with enterprise architecture standards and maintain a secure, governable integration landscape.', 'solution_architect', 'solution_architect', NULL, 'IMMEDIATE', NULL, 'proposed', ARRAY['{''cons'': [''Potential for slight latency increase.'', ''Dependency on API Gateway availability.''], ''pros'': [''Centralized security, monitoring, and policy enforcement.'', ''Compliance with enterprise standard INT-01.'', ''Simplified integration management.'', ''Reduced technical debt.''], ''description'': ''Route all integrations through the enterprise API Gateway.'', ''option_label'': ''A''}', '{''cons'': [''Violates enterprise standard INT-01.'', ''Creates security blind spots.'', ''Inconsistent policy enforcement.'', ''Increased operational complexity.'', ''Requires explicit EA waiver for each exception.''], ''pros'': [''Potentially lower latency for specific high-throughput internal integrations.''], ''description'': ''Allow direct peer-to-peer integrations for specific use cases.'', ''option_label'': ''B''}']::text[], ARRAY['Performance tuning of the API Gateway.', 'Ensure adequate capacity planning for the API Gateway.']::text[], ARRAY['INT-F03']::text[], ARRAY[]::text[], ARRAY['KB-03 | INT-01']::text[], 'NOW()', 'NOW()');
INSERT INTO adrs (id, review_id, adr_id, domain, adr_type, title, decision, rationale, context, owner, proposed_owner, target_date, proposed_target_date, waiver_expiry_date, status, options_considered, mitigations, links_to_finding_ids, links_to_action_ids, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'ADR-APP-01', 'APP', 'new_decision', 'Decision: Microservices Architecture on AWS for EDMS', 'The EDMS will be implemented as a cloud-native, microservices-based platform hosted on AWS. Each service will be independently deployable and own its data, exposing defined interfaces.', 'This decision aligns with modern cloud-native best practices (KB-02) and enables independent development, deployment, and scaling of EDMS components, fostering agility and resilience.', 'The EDMS requires a flexible and scalable architecture to manage a high volume of documents and evolving business needs. A microservices approach was considered to break down the system into manageable, independently deployable units.', 'solution_architect', 'solution_architect', NULL, 'IMMEDIATE', NULL, 'proposed', ARRAY['{''cons'': [''Difficult to scale individual components.'', ''Slower development cycles due to tight coupling.'', ''Higher risk of widespread impact from a single failure.''], ''pros'': [''Simpler initial development and deployment.'', ''Easier to manage transactions across components.''], ''description'': ''Monolithic Architecture on AWS'', ''option_label'': ''A''}', '{''cons'': [''Increased operational complexity (deployment, monitoring, management).'', ''Challenges with distributed transactions and data consistency.'', ''Requires mature DevOps practices.''], ''pros'': [''Independent deployability and scalability of services.'', ''Technology diversity possible per service.'', ''Improved fault isolation.'', ''Faster development cycles for individual services.''], ''description'': ''Microservices Architecture on AWS (Chosen)'', ''option_label'': ''B''}']::text[], ARRAY['Implement robust inter-service communication patterns (e.g., asynchronous messaging, resilient REST APIs).', 'Establish comprehensive monitoring and tracing for distributed services.', 'Invest in automation for deployment and operations.', 'Carefully manage data consistency across services.']::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['KB-02']::text[], 'NOW()', 'NOW()');
INSERT INTO adrs (id, review_id, adr_id, domain, adr_type, title, decision, rationale, context, owner, proposed_owner, target_date, proposed_target_date, waiver_expiry_date, status, options_considered, mitigations, links_to_finding_ids, links_to_action_ids, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'ADR-INF-01', 'INF', 'new_decision', 'Decision: Use AWS EKS as the container orchestration platform', 'AWS Elastic Kubernetes Service (EKS) is selected as the managed Kubernetes platform for the EDMS solution.', 'Leveraging a managed Kubernetes service reduces operational overhead for cluster management, security patching, and availability, aligning with the principle of ''Reuse, Buy, Build'' (G-07) and standardizing on enterprise-approved cloud-native platforms.', 'The EDMS solution requires a robust, scalable, and secure container orchestration platform. The choice between self-managed Kubernetes, another cloud provider''s managed service, or AWS EKS was considered.', 'solution_architect', 'solution_architect', '2026-05-11', 'IMMEDIATE', NULL, 'proposed', ARRAY['{''cons'': [''Significant operational overhead for cluster management, patching, and availability.'', ''Requires specialized expertise.'', ''Slower to adopt new Kubernetes features.''], ''pros'': [''Full control over the cluster configuration.'', ''Potentially lower direct infrastructure cost if managed efficiently.''], ''description'': ''Self-managed Kubernetes on EC2 instances'', ''option_label'': ''A''}', '{''cons'': [''Less control over the control plane.'', ''Potential for vendor lock-in with AWS.'', ''Can be more expensive than self-managed if not optimized.''], ''pros'': [''Managed control plane reduces operational burden.'', ''High availability and security features are built-in.'', ''Seamless integration with other AWS services.'', ''Faster adoption of new Kubernetes versions.''], ''description'': ''AWS Elastic Kubernetes Service (EKS)'', ''option_label'': ''B''}', '{''cons'': [''Requires multi-cloud expertise if not already standardized.'', ''Potential integration challenges with existing AWS-based services.'', ''May not align with current enterprise cloud strategy.''], ''pros'': [''Managed service benefits similar to EKS.'', ''Leverages different cloud provider ecosystems.''], ''description'': ''Azure Kubernetes Service (AKS) / Google Kubernetes Engine (GKE)'', ''option_label'': ''C''}']::text[], ARRAY['Utilize Infrastructure as Code (AWS CDK) to abstract and manage EKS resources, facilitating potential future migration.', 'Adhere to open standards where possible within the EKS environment (e.g., Kubernetes APIs, Istio).']::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['KB-07 | None - Infrastructure as Code', 'KB-10 | G-03 Think Globally, Act Locally']::text[], 'NOW()', 'NOW()');
INSERT INTO adrs (id, review_id, adr_id, domain, adr_type, title, decision, rationale, context, owner, proposed_owner, target_date, proposed_target_date, waiver_expiry_date, status, options_considered, mitigations, links_to_finding_ids, links_to_action_ids, kb_references, created_at, updated_at) VALUES (gen_random_uuid(), :'target_review_id'::uuid, 'ADR-DSO-01', 'DSO', 'new_decision', 'Decision: Use GitHub Actions for CI/CD Orchestration and ArgoCD for Deployment', 'The CI/CD pipeline will be orchestrated using GitHub Actions for build, test, and security scanning stages, with ArgoCD used for GitOps-based deployment to various environments.', 'This decision leverages existing enterprise tooling (GitHub Actions) and a proven GitOps deployment tool (ArgoCD), aligning with the principle of using established platforms where possible and enabling a fully automated, auditable deployment process.', 'The EDMS solution requires a robust and automated CI/CD pipeline to support its DevSecOps principles, including shift-left security and GitOps. A decision was needed on the specific tools to orchestrate these processes.', 'solution_architect', 'solution_architect', NULL, 'IMMEDIATE', NULL, 'proposed', ARRAY['{''cons'': [''GitHub Actions deployment capabilities might be less mature or feature-rich than dedicated GitOps tools for complex environments.'', ''May require more custom scripting for advanced deployment strategies.''], ''pros'': [''Single toolchain simplifies integration.'', ''Leverages existing GitHub Actions expertise.''], ''description'': ''Use GitHub Actions for full CI/CD lifecycle including deployment orchestration.'', ''option_label'': ''A''}', '{''cons'': [''Introduces a new toolchain, increasing complexity and integration effort.'', ''Requires expertise in both Jenkins and Spinnaker.''], ''pros'': [''Jenkins is a mature and widely adopted CI/CD tool.'', ''Spinnaker offers advanced deployment strategies.''], ''description'': ''Use Jenkins for CI/CD orchestration and a separate tool (e.g., Spinnaker) for deployment.'', ''option_label'': ''B''}', '{''cons'': [''Requires integration effort between GitHub Actions and ArgoCD.'', ''Learning curve for ArgoCD.''], ''pros'': [''Leverages GitHub Actions for build/test/scan stages.'', ''ArgoCD provides robust GitOps deployment capabilities.'', ''Clear separation of concerns.'', ''Aligns with GitOps best practices.''], ''description'': ''Use GitHub Actions for CI/CD orchestration and ArgoCD for deployment (Chosen Option).'', ''option_label'': ''C''}']::text[], ARRAY['Provide comprehensive training on ArgoCD for the development and operations teams.', 'Implement thorough integration testing between GitHub Actions and ArgoCD to ensure seamless pipeline execution.', 'Maintain clear documentation for the CI/CD pipeline configuration and deployment process.']::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['KB-02 | CI/CD Pipeline']::text[], 'NOW()', 'NOW()');
